local p = {}
function p.main (frame) local content = mw.title.getCurrentTitle():getContent() local offset = string.find(content, "==", 1 , true) lead = string.sub(content, 1, offset-1) if string.find(lead, frame.args[1], 1, true) then return "true" else return "false" end end
return p

