local p = {}
function p.main (frame) local content = mw.title.getCurrentTitle():getContent() local offset = string.find(content, "==", 1 , true) if offset then lead = string.sub(content, 1, offset-1) if (string.find(lead, frame.args[1], 1, true)) then iter = string.gmatch(lead, "infobox") iter() if not iter() then --if able to find two infoboxes, then don't return true return "true" end end end end
return p

